'use strict';
({params, imports}) => {
  const encounter = params.entity;
  const formElement = params.formElement;
  const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({encounter, formElement});
  //read the value of form element using encounter.getObservationValue(CONCEPT_NAME);
  const formElementValue1 = "1";
  const formElementValue2 = "1";
  //form element will be shown only when below condition is true
  const showCondition = formElementValue1 === formElementValue2;
  statusBuilder.show().whenItem(showCondition).is.truthy;
  //for form element validation error
  if(!showCondition){
  statusBuilder.validationError("Values are not equal");
  }
  return statusBuilder.build();
};

"use strict";
({ params, imports }) => {
  const individual = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({individual});

  const isGrievanceFollowUpEncounterAlreadyPresent = individual.getEncounters().filter(encounter => 
      (encounter.name === 'FC Action Item Follow Up for Field Coordinator' || encounter.name === 'Action Item Follow Up for Cluster Coordinator (CC)') && encounter.encounterDateTime && !encounter.cancelDateTime
  ).length > 0;

  const isGrievanceFollowUpForFCAlreadyScheduled = individual.getEncounters().filter(encounter => 
      encounter.name === 'FC Action Item Follow Up for Field Coordinator' && encounter.earliestVisitDateTime && !encounter.cancelDateTime
  ).length > 0;

  const isGrievanceFollowUpForCCAlreadyScheduled = individual.getEncounters().filter(encounter => 
      encounter.name === 'FC Action Item Follow Up for Field Coordinator' && encounter.earliestVisitDateTime && !encounter.cancelDateTime
  ).length > 0;

  const condition11 = new imports.rulesConfig.RuleCondition({individual}).when.valueInRegistration("89939e7d-ead8-4ed9-997f-8f1223df7634").defined.matches();

  if(condition11 && !isGrievanceFollowUpEncounterAlreadyPresent){
    if(individual.getObservationReadableValue('7ea54c7a-c857-4c7b-b403-e81bfaa762e1') === 'SMC' && !isGrievanceFollowUpForCCAlreadyScheduled) {
      const earliestDate = moment(individual.getObservationReadableValue('89939e7d-ead8-4ed9-997f-8f1223df7634')).add(6,'H').add(0, 'days').toDate();
      const maxDate = moment(individual.getObservationReadableValue('89939e7d-ead8-4ed9-997f-8f1223df7634')).add(6,'H').add(1, 'days').toDate();
      scheduleBuilder.add({name: "FC Action Item Follow Up for Field Coordinator", encounterType: "FC Action Item Follow Up for Field Coordinator", earliestDate, maxDate});  
    }
    else if(individual.getObservationReadableValue('7ea54c7a-c857-4c7b-b403-e81bfaa762e1') !== 'SMC' && !isGrievanceFollowUpForFCAlreadyScheduled) {
      const earliestDate = moment(individual.getObservationReadableValue('89939e7d-ead8-4ed9-997f-8f1223df7634')).add(6,'H').add(0, 'days').toDate();
      const maxDate = moment(individual.getObservationReadableValue('89939e7d-ead8-4ed9-997f-8f1223df7634')).add(6,'H').add(1, 'days').toDate();
      scheduleBuilder.add({name: "Action Item Follow Up for Cluster Coordinator (CC)", encounterType: "Action Item Follow Up for Cluster Coordinator (CC)", earliestDate, maxDate});  
    }
  }

  return scheduleBuilder.getAll();
};

