  const isFollowUpDateDefined = new imports.rulesConfig.RuleCondition({individual, formElement}).when.valueInRegistration("89939e7d-ead8-4ed9-997f-8f1223df7634").defined.matches();

  if(isFollowUpDateDefined){
    const followUpDate = moment(individual.getObservationValue('89939e7d-ead8-4ed9-997f-8f1223df7634')).startOf('day');
    const currentDate = moment().startOf('day');
    if(followUpDate.isBefore(currentDate)){
      validationErrors.push('Follow up date cannot be a past date');
    }
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

