      const maxDate = moment(earliestDate).add(25, 'days').toDate();
      scheduleBuilder.add({
        name: "Activity Monthly Status",
        encounterType: "Activity Monthly Status",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
};

