  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
    encounter
  });
  // Check if there is already a scheduled encounter of "Library Monthly Report" excluding the current one
    const isAlreadyScheduledEncounter = encounter.individual.scheduledEncountersOfType('Anganwadi Profile') ? encounter.individual.scheduledEncountersOfType('Anganwadi Profile').filter(enc => !_.isEqual(enc.uuid, encounter.uuid)) : [] ;

    // Proceed only if no similar encounter is already scheduled
    if (isAlreadyScheduledEncounter.length === 0) {


  const individual = encounter.individual;

  const getNextApril = (date) => {
    const year = moment(date).add(6,'H').year()
    return moment({year: year + 1, month: 3, day: 1});
  }

  function isVisitAlreadyScheduled(encounterType, earliestDate) {
    return individual.getEncounters().filter((enc) => 
        enc.encounterType.name === encounterType && 
        enc.voided === false &&
        moment(enc.earliestVisitDateTime).add(6,'H').startOf('day').isSame(earliestDate, 'day')
      ).length > 0;
  }

  const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
  const earliestDateForAnganwadiProfile = getNextApril(visitDate);

  if(isVisitAlreadyScheduled("Anganwadi Profile", earliestDateForAnganwadiProfile) == false){ 
    const earliestDate = moment(earliestDateForAnganwadiProfile).add(6,'H').toDate();

    const nextYear = moment(earliestDate).year() + 1;
    const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').subtract(6, 'H').toDate();

    scheduleBuilder.add({ 
      name: "Anganwadi Profile", 
      encounterType: "Anganwadi Profile", 
      earliestDate,
      maxDate
    });
  }
}

  return scheduleBuilder.getAll();
};

