"use strict";
({params, imports}) => {
    const individual = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        individual
    });

    const isAnganwadiMonthlyRecordsEncounterAlreadyPresent = individual.getEncounters().filter(enc =>
        enc.name === 'Anganwadi Monthly Records' && enc.encounterDateTime && !enc.cancelDateTime && !enc.voided
    ).length > 0;

    if (!isAnganwadiMonthlyRecordsEncounterAlreadyPresent) {
        const firstDayOfNextMonth = moment(individual.registrationDate).add(1, 'months').startOf('month');
        const earliestDate = firstDayOfNextMonth.toDate();
        const maxDate = firstDayOfNextMonth.add(25, 'days').toDate();
        scheduleBuilder.add({
            name: "Anganwadi Monthly Records",
            encounterType: "Anganwadi Monthly Records",
            earliestDate,
            maxDate
        });
    }



     const getApril = (date) => {
    const month = moment(date).month();
    const year = moment(date).year()
    if(month<3) return moment({year:year-1,month:3,day:1});
    return moment({year:year,month:3,day:1});
}
const getOverdueDate=(earliestDate)=>{
 const nextYear = moment(earliestDate).year() + 1;
 const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').subtract(6, 'H').toDate();

 return maxDate;
}


    function isVisitAlreadyScheduled(encounterType, earliestDate) {
        return individual.getEncounters().filter((enc) =>
            enc.encounterType.name === encounterType &&
            enc.voided === false &&
            moment(enc.earliestVisitDateTime).startOf('day').isSame(earliestDate, 'day')
        ).length > 0;
    }

    const earliestDateForAnganwadiProfile = getApril(individual.registrationDate);
    if (isVisitAlreadyScheduled("Anganwadi Profile", earliestDateForAnganwadiProfile) == false) {
        const earliestDate = earliestDateForAnganwadiProfile.toDate();
        const maxDate = getOverdueDate(earliestDate);
        scheduleBuilder.add({
            name: "Anganwadi Profile",
            encounterType: "Anganwadi Profile",
            earliestDate,
            maxDate
        });
    }

    const scheduledOrCompletedEncountersOfType = (type) => {
        const data = individual.encounters.filter((enc) => enc.encounterType.name === type && enc.voided == false && enc.cancelDateTime == null);
        return data;
    }

    const condition20 = scheduledOrCompletedEncountersOfType("Anganwadi Teacher Capacity Building").length > 0;
    if (!condition20) {
        const earliestDate = moment(individual.registrationDate).add(1, 'M').startOf('month').toDate();
        const maxDate = moment(earliestDate).add(25, 'd').toDate();
        scheduleBuilder.add({
            name: "Anganwadi Teacher Capacity Building",
            encounterType: "Anganwadi Teacher Capacity Building",
            earliestDate,
            maxDate
        });
    }

    return scheduleBuilder.getAll();
};

