"use strict";
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({encounter});

    const encounters = encounter.individual.getEncounters();

    const nextEarliestDate = moment(encounter.earliestVisitDateTime).add(6, 'hours').add(1, 'months').startOf('month').add(6, 'hours');

    const isEncounterAlreadyPresent = encounters.some(enc => 
        !enc.voided && 
        enc.encounterType.name === 'Anganwadi Teacher Capacity Building' && 
        moment(enc.earliestVisitDateTime).add(6, 'hours').isSame(nextEarliestDate, 'day')
    );

    if (!isEncounterAlreadyPresent) {
        const earliestDate = nextEarliestDate.toDate();
        const maxDate = moment(earliestDate).add(25, 'days').toDate();

        scheduleBuilder.add({
            name: "Anganwadi Teacher Capacity Building", encounterType: "Anganwadi Teacher Capacity Building", earliestDate, maxDate
        });
    }

    return scheduleBuilder.getAll();
};

"use strict";
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
    encounter
  });

  // Add new visit schedule object to scheduleBuilder
  const scheduledOrCompletedEncountersOfType = (type, nextVisitDate) => {
    const nextDateMonth = moment(nextVisitDate).add(6, 'hours').month();
    const nextDateYear = moment(nextVisitDate).add(6, 'hours').year();
    const data = encounter.individual.encounters.filter(
      (enc) =>
        enc.encounterType.name === type &&
        enc.voided == false &&
        enc.cancelDateTime == null &&
        moment(enc.earliestVisitDateTime).add(6, 'hours').year() == nextDateYear &&
        moment(enc.earliestVisitDateTime).add(6, 'hours').month() == nextDateMonth
    );
    return data;
  };

  const msm_date = moment(encounter.earliestVisitDateTime)
    .add(6, 'hours')
    .add(1, 'months')
    .startOf('month')
    .add(6, 'hours')
    .toDate();
  const condition11 = scheduledOrCompletedEncountersOfType(
    "Anganwadi Teacher Capacity Building",
    msm_date
  ).length > 0;

  if (!condition11) {
    const earliestDate = msm_date;
    const maxDate = moment(earliestDate).add(25, "d").toDate();
    scheduleBuilder.add({
      name: "Anganwadi Teacher Capacity Building",
      encounterType: "Anganwadi Teacher Capacity Building",
      earliestDate,
      maxDate
    });
  }

  return scheduleBuilder.getAll();
};

