"use strict";
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({encounter});

    const encounters = encounter.individual.getEncounters();

    const nextEarliestDate = moment(encounter.earliestVisitDateTime).add(1, 'months').startOf('month');

    const isEncounterAlreadyPresent = encounters.some(enc => 
        !enc.voided && 
        enc.encounterType.name === 'Block Monthly Record' && 
        moment(enc.earliestVisitDateTime).isSame(nextEarliestDate, 'day')
    );

    if (!isEncounterAlreadyPresent) {
        const earliestDate = nextEarliestDate.toDate();
        const maxDate = moment(earliestDate).add(26, 'days').toDate();

        scheduleBuilder.add({
            name: "Block Monthly Record", encounterType: "Block Monthly Record", earliestDate, maxDate
        });
    }

    return scheduleBuilder.getAll();
};

