"use strict";
({ params, imports }) => {
  const individual = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({individual});

  const isCRPCapacityBuildingEncounterAlreadyPresent = individual.getEncounters().filter(enc =>
    enc.encounterType.name === 'CRP/BRPs Capacity Building' && !enc.voided).length > 0;

  if (!isCRPCapacityBuildingEncounterAlreadyPresent) {
    const firstDayOfNextMonth = moment(individual.registrationDate).add(1, 'months').startOf('month');
    const earliestDate = firstDayOfNextMonth.toDate();
    const maxDate = firstDayOfNextMonth.add(25, 'days').toDate();
    scheduleBuilder.add({name: "CRP/BRPs Capacity Building", encounterType: "CRP/BRPs Capacity Building", earliestDate, maxDate});
  }

  const scheduledOrCompletedEncountersOfType = (type) => {
    const data = individual.encounters.filter((enc) => enc.encounterType.name === type && enc.voided == false && enc.cancelDateTime == null);
    return data;
  }

  const condition21 = scheduledOrCompletedEncountersOfType("Block Monthly Record").length > 0;

  if (!condition21) {
    const earliestDate = moment(individual.registrationDate).add(1,'M').startOf('month').toDate();
    const maxDate = moment(earliestDate).add(26,'d').toDate();
    scheduleBuilder.add({name: "Block Monthly Record", encounterType: "Block Monthly Record", earliestDate, maxDate});
  }


  return scheduleBuilder.getAll();
};

