"use strict";
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
    encounter
  });

const getApril = (date) => {
        const month = moment(date).month();
        const year = moment(date).year()
        if(month<3) return moment({year:year-1,month:3,day:1});
        return moment({year:year,month:3,day:1});
    }
    const getOverdueDate=(earliestDate)=>{
     const nextYear = moment(earliestDate).year() + 1;
     const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').subtract(6, 'H').toDate();

     return maxDate;
    }

  const scheduledOrCompletedEncountersOfType = (type, nextVisitDate) => {
    const nextDateMonth = moment(nextVisitDate).month();
    const nextDateYear = moment(nextVisitDate).year();
    const data = encounter.individual.encounters.filter((enc) =>
      enc.encounterType.name === type &&
      enc.voided == false &&
      moment(enc.earliestVisitDateTime).year() == nextDateYear &&
      moment(enc.earliestVisitDateTime).month() == nextDateMonth
    );
    return data;
  };

  const nextVisitDate = getApril(moment(encounter.earliestVisitDateTime));
  const earliestDate = nextVisitDate.add(6, 'H').add(1,'y').toDate();
  const isVisitAlreadyScheduled = scheduledOrCompletedEncountersOfType("Library Space and Collection - Library Profiling", earliestDate).length > 0;

  if (!isVisitAlreadyScheduled) {

   const maxDate = getOverdueDate(earliestDate)

    scheduleBuilder.add({ name: "Library Space and Collection - Library Profiling", encounterType: "Library Space and Collection - Library Profiling", earliestDate, maxDate });
  }

  return scheduleBuilder.getAll();
};

