"use strict";
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ encounter });
  const individual = encounter.individual;

  // Check if there is already a scheduled encounter of "Library Space and Collection - Library Profiling" excluding the current one
  const isAlreadyScheduledEncounter = encounter.individual.scheduledEncountersOfType('Library Space and Collection - Library Profiling')
    ? encounter.individual.scheduledEncountersOfType('Library Space and Collection - Library Profiling').filter(enc => !_.isEqual(enc.uuid, encounter.uuid))
    : [];

  // Proceed only if no similar encounter is already scheduled
  if (isAlreadyScheduledEncounter.length === 0) {
    const getNextApril = (date) => {
      const year = moment(date).add(6, 'H').year();
      return moment({ year: year + 1, month: 3, day: 1 });
    };

    const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
    const earliestDate = getNextApril(visitDate).add(6, 'H').toDate();

    const isVisitAlreadyScheduled = individual.getEncounters(true).filter((enc) =>
      enc.encounterType.name === 'Library Space and Collection - Library Profiling' &&
      enc.voided === false &&
      moment(enc.earliestVisitDateTime).add(6, 'H').startOf('day').isSame(moment(earliestDate), 'day')
    ).length === 0;

    if (isVisitAlreadyScheduled) {

      const nextYear = moment(earliestDate).year() + 1;
      const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').subtract(6, 'H').toDate();

      scheduleBuilder.add({
        name: "Library Space and Collection - Library Profiling",
        encounterType: "Library Space and Collection - Library Profiling",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
};

