'use strict';
({params, imports}) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const wasPTMConducted = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.valueInEncounter("510566f1-8efb-4e19-8225-34e02e98664b").containsAnswerConceptName("874d4f0c-817f-4b79-8382-d5d5567ea958").matches();


  visibility = wasPTMConducted;

  const isDateDefined = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.valueInEncounter("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb").defined.matches();

    if (isDateDefined) {
        const selectedDate = moment(encounter.getObservationReadableValue("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb"));
        const currentDate = moment(); 

        if (selectedDate.isAfter(currentDate, 'day')) {
            validationErrors.push("Date cannot be after the current date");
        } 
        else {
            const currentEncUUID = encounter.uuid;
            const encounterAlreadyFilled = encounter.individual.getEncounters(true).some((enc) => {
                const selectedEncDate = moment(enc.getObservationReadableValue("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb"));
                const wasEncounterFilled = enc.getObservationReadableValue("510566f1-8efb-4e19-8225-34e02e98664b") === 'Yes';
                return enc.encounterType.name === "PTM" && enc.encounterDateTime != null && enc.uuid !== currentEncUUID && wasEncounterFilled && selectedDate.isSame(selectedEncDate, 'month'); 
            });
            if(encounterAlreadyFilled) {
                validationErrors.push("This form is already filled for this month");
            }
        }
    }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

