        .utcOffset("+05:30")
        .add(1, "month")
        .startOf("month")
        .utc();

    const hasScheduledOrCompletedEncounterOfType = (type, nextVisitDate) => {
        const nextMonth = nextVisitDate.month();
        const nextYear = nextVisitDate.year();

        return encounter.individual.encounters.some(enc => {
            if (enc.voided || enc.encounterType.name != type) return false;

            const encDate = enc.earliestVisitDateTime || enc.encounterDateTime || enc.cancelDateTime;
            if (!encDate) return false;

            const normalized = moment(encDate)
                .utcOffset("+05:30")
                .startOf("month")
                .utc();

            return normalized.year() == nextYear && normalized.month() == nextMonth;
        });
    };

    const alreadyExists = hasScheduledOrCompletedEncounterOfType("SMC School Monitoring", nextDate);

    if (!alreadyExists) {
        const earliestDate = nextDate.toDate();
        const maxDate = moment(earliestDate).add(25, "days").toDate();

        scheduleBuilder.add({
            name: "SMC School Monitoring",
            encounterType: "SMC School Monitoring",
            earliestDate,
            maxDate
        });
    }

    return scheduleBuilder.getAll();
};

