"use strict";
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
    encounter
  });

  // Check if there is already a scheduled encounter of "School Annual Form" excluding the current one
  const isAlreadyScheduledEncounter = encounter.individual.scheduledEncountersOfType('School Annual Form')
    ? encounter.individual.scheduledEncountersOfType('School Annual Form').filter(enc => !_.isEqual(enc.uuid, encounter.uuid)) : [];

  // Proceed only if no similar encounter is already scheduled
  if (isAlreadyScheduledEncounter.length === 0) {

    //add new visit schedule object to scheduleBuilder
    const getNextApril = (date) => {
      const month = moment(date).add(6, 'H').month();
      const year = moment(date).add(6, 'H').year();
      if (month < 3) return moment({ year: year, month: 3, day: 1 });
      return moment({ year: year + 1, month: 3, day: 1 });
    };

    const scheduledOrCompletedEncountersOfType = (type, nextVisitDate) => {
      const nextDateMonth = moment(nextVisitDate).month();
      const nextDateYear = moment(nextVisitDate).year();
      const data = encounter.individual.encounters.filter((enc) =>
        enc.encounterType.name === type &&
        enc.voided == false &&
        enc.cancelDateTime == null &&
        moment(enc.earliestVisitDateTime).add(6, 'H').year() == nextDateYear &&
        moment(enc.earliestVisitDateTime).add(6, 'H').month() == nextDateMonth
      );
      return data;
    };

    const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
    const annual_date = getNextApril(visitDate);
    const condition11 = scheduledOrCompletedEncountersOfType('School Annual Form', annual_date).length > 0;

    if (!condition11) {
      const earliestDate = moment(annual_date).add(6, 'H').toDate();

      const nextYear = moment(earliestDate).year() + 1;
      const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').subtract(6, 'H').toDate();

      scheduleBuilder.add({
        name: "School Annual Form",
        encounterType: "School Annual Form",
        earliestDate,
        maxDate
      });
    }
  }

  return scheduleBuilder.getAll();
};

