"use strict";
({params, imports}) => {
    const individual = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({individual});

    const isLibraryMonthlyReportEncounterAlreadyPresent = individual.getEncounters().filter(encounter =>
        encounter.name === 'Library Monthly Report' && encounter.encounterDateTime && !encounter.cancelDateTime && !encounter.voided
    ).length > 0;

    if (!isLibraryMonthlyReportEncounterAlreadyPresent) {
        const firstDayOfNextMonth = moment(individual.registrationDate).utcOffset("+05:30").add(1, 'months').startOf('month').add(1, "D").utc().toDate();
        const earliestDate = firstDayOfNextMonth;
        const maxDate = moment(firstDayOfNextMonth).add(25, 'days').toDate();
        scheduleBuilder.add({
            name: "Library Monthly Report",
            encounterType: "Library Monthly Report",
            earliestDate,
            maxDate
        });
    }

    const isSMCSchoolMonitoringEncounterAlreadyPresent = individual.getEncounters().filter(encounter =>
        encounter.name === 'SMC School Monitoring' && encounter.encounterDateTime && !encounter.cancelDateTime && !encounter.voided
    ).length > 0;

    if (!isSMCSchoolMonitoringEncounterAlreadyPresent) {
        const firstDayOfNextMonth = moment(individual.registrationDate).utcOffset("+05:30").add(1, 'months').startOf('month').add(1, "D").utc().toDate();
        const earliestDate = firstDayOfNextMonth;
        const maxDate = moment(firstDayOfNextMonth).add(25, 'days').toDate();
        scheduleBuilder.add({
            name: "SMC School Monitoring",
            encounterType: "SMC School Monitoring",
            earliestDate,
            maxDate
        });
    }

    const getApril = (date) => {
        const month = moment(date).utcOffset("+05:30").month();
        const year = moment(date).utcOffset("+05:30").year();
        if(month < 3) {
            return moment({year: year-1, month: 3, day: 1}).utcOffset("+05:30").add(1, "D").utc();
        }
        return moment({year: year, month: 3, day: 1}).utcOffset("+05:30").add(1, "D").utc();
    };

    const getOverdueDate = (earliestDate) => {
        const nextYear = moment(earliestDate).year() + 1;
        const maxDate = moment().set({ year: nextYear, month: 2 }).endOf('month').utcOffset("+05:30").subtract(6, 'H').utc().toDate();
        return maxDate;
    };

    const scheduledOrCompletedEncountersOfType = (type) => {
        const data = individual.encounters.filter((enc) => 
            enc.encounterType.name === type && enc.voided == false && enc.cancelDateTime == null
        );
        return data;
    };

    const condition21 = scheduledOrCompletedEncountersOfType("Monthly School Monitoring").length > 0;

    if(!condition21) {
        const earliestDate = moment(individual.registrationDate).utcOffset("+05:30").add(1, 'M').startOf('month').add(1, "D").utc().toDate();
        const maxDate = moment(earliestDate).add(25, 'd').toDate();
        scheduleBuilder.add({
            name: "Monthly School Monitoring", 
            encounterType: "Monthly School Monitoring", 
            earliestDate, 
            maxDate
        });
    }

    const condition41 = scheduledOrCompletedEncountersOfType("School Annual Form").length > 0;

    if(!condition41) {
        const earliestDate = getApril(individual.registrationDate).toDate();
        const maxDate = getOverdueDate(earliestDate);
        scheduleBuilder.add({
            name: "School Annual Form", 
            encounterType: "School Annual Form", 
            earliestDate, 
            maxDate
        });
    }

    const isLibraryEncounterDone = scheduledOrCompletedEncountersOfType("Library Space and Collection - Library Profiling").length === 0;

    if(isLibraryEncounterDone) {
        const earliestDate = getApril(individual.registrationDate).toDate();
        const maxDate = getOverdueDate(earliestDate);
        scheduleBuilder.add({
            name: "Library Space and Collection - Library Profiling", 
            encounterType: "Library Space and Collection - Library Profiling", 
            earliestDate, 
            maxDate
        });
    }

    const condition22 = scheduledOrCompletedEncountersOfType("School Teacher Capacity Building").length > 0;
    if (!condition22) {
        const earliestDate = moment(individual.registrationDate).utcOffset("+05:30").add(1, 'M').startOf('month').add(1, "D").utc().toDate();
        const maxDate = moment(earliestDate).add(25, 'd').toDate();
        scheduleBuilder.add({
            name: "School Teacher Capacity Building", 
            encounterType: "School Teacher Capacity Building", 
            earliestDate, 
            maxDate
        });
    }

    return scheduleBuilder.getAll();
};

'use strict';
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];

    const isDateDefined = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.valueInEncounter("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb").defined.matches();

    if (isDateDefined) {
        const selectedDate = moment(encounter.getObservationReadableValue("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb"));
        const currentDate = moment(); 

        if (selectedDate.isAfter(currentDate, 'day')) {
            validationErrors.push("Date cannot be after the current date");
        } 
        else {
            const currentEncUUID = encounter.uuid;
            const encounterAlreadyFilled = encounter.individual.getEncounters(true).some((enc) => {
                const selectedEncDate = moment(enc.getObservationReadableValue("8c68ee2e-73c8-42bd-9252-a15d2c9e2ecb"));
                return enc.encounterType.name === "School Student Assessment" && enc.encounterDateTime != null && enc.uuid !== currentEncUUID && selectedDate.isSame(selectedEncDate, 'month'); 
            });
            if(encounterAlreadyFilled) {
                validationErrors.push("This form is already filled for this month");
            }
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

