    const data = encounter.individual.encounters.filter((enc)=> enc.encounterType.name === type && enc.voided == false && enc.cancelDateTime == null && moment(enc.earliestVisitDateTime).year()==nextDateYear  && moment(enc.earliestVisitDateTime).month()==nextDateMonth )
    return data;
}


const annual_date = getNextApril(encounter.earliestVisitDateTime);
const condition11 = scheduledOrCompletedEncountersOfType('School Annual Form',annual_date).length > 0 ;


if(!condition11){
    const earliestDate = annual_date.toDate();
    const maxDate = moment(earliestDate).add(25,'d').toDate();
    scheduleBuilder.add({name: "School Annual Form", encounterType: "School Annual Form", earliestDate, maxDate});  
}

  return scheduleBuilder.getAll();
};

