"use strict";
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({encounter});

    // Check if there is already a scheduled encounter of "Volunteer Monthly Report" excluding the current one
    const isAlreadyScheduledEncounter = encounter.individual.scheduledEncountersOfType('Volunteer Monthly Report') ? encounter.individual.scheduledEncountersOfType('Volunteer Monthly Report').filter(enc => !_.isEqual(enc.uuid, encounter.uuid)) : [] ;

    // Proceed only if no similar encounter is already scheduled
    if (isAlreadyScheduledEncounter.length === 0) {

    const scheduledOrCompletedEncountersOfType = (type, nextVisitDate) => {
      const nextDateMonth = moment(nextVisitDate).month();
      const nextDateYear = moment(nextVisitDate).year();

      const data = encounter.individual.encounters.filter((enc) =>
        enc.encounterType.name === type &&
        enc.voided == false &&
        enc.cancelDateTime == null &&
        moment(enc.earliestVisitDateTime).year() == nextDateYear &&
        moment(enc.earliestVisitDateTime).month() == nextDateMonth
      );
      return data;
    };

    const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
    const nextDate = moment(visitDate).add(6, 'H').add(1, 'M').startOf('month').add(6, 'H').toDate();
    const condition11 = scheduledOrCompletedEncountersOfType("Volunteer Monthly Report", nextDate).length > 0;

    if (!condition11) {
        const earliestDate = nextDate;
        const maxDate = moment(earliestDate).add(25, 'days').toDate();
        scheduleBuilder.add({
            name: "Volunteer Monthly Report", encounterType: "Volunteer Monthly Report", earliestDate, maxDate
        });
     }
  }

    return scheduleBuilder.getAll();
};

