({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ encounter });
  const individual = encounter.individual;

  // Check if there is already a scheduled encounter of "Activity Monthly Status" excluding the current one
  const isAlreadyScheduledEncounter = encounter.individual.scheduledEncountersOfType('Activity Monthly Status')
    ? encounter.individual.scheduledEncountersOfType('Activity Monthly Status').filter(enc => !_.isEqual(enc.uuid, encounter.uuid))
    : [];

  // Proceed only if no similar encounter is already scheduled
  if (isAlreadyScheduledEncounter.length === 0) {
    const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
    const earliestDate = moment(visitDate).add(6, 'H').add(1, 'M').startOf('month').add(6, 'H').toDate();

