                return enc.encounterType.name === "Onsite Support To Teachers" && enc.encounterDateTime != null && enc.uuid !== currentEncUUID && selectedDate.isSame(selectedEncDate, 'month'); 
            });
            if(encounterAlreadyFilled) {
                validationErrors.push("This form is already filled for this month");
            }
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
