'use strict';
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = 0;
  let answersToSkip = [];
  let validationErrors = [];

  const isTotalChildrenDefined = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.valueInEncounter("5e2540d7-494c-4f46-8f98-4d601a140e9e").defined
    .and.when.valueInEncounter("25427c04-d95e-4c9e-a49a-16592b5ee837").defined
    .and.when.valueInEncounter("d0b2b320-340e-49aa-95bd-a07464f41c5b").defined
    .and.when.valueInEncounter("29ddc822-a7bb-4b4d-818e-079cc12fa3d1").defined
    .and.when.valueInEncounter("e1b1d58f-da4e-4921-b480-c9c70c9ceac2").defined
    .and.when.valueInEncounter("5390d56b-1211-4229-997a-96710ffc6871").defined
    .and.when.valueInEncounter("492e8791-720c-4563-9de1-b326e71b0cc9").defined
    .and.when.valueInEncounter("c8fb85af-7057-4755-9bbf-3e7db2ec1fbd").defined
    .and.when.valueInEncounter("33f1b340-e0b9-4da2-8ec6-78a33a20ca22").defined
    .and.when.valueInEncounter("a410999a-cdcd-4a1d-adc1-4c2625dbe5b5").defined.matches();


  visibility = isTotalChildrenDefined;

  if(isTotalChildrenDefined){

    const totalBoysPlusTotalGirls = encounter.getObservationReadableValue("5e2540d7-494c-4f46-8f98-4d601a140e9e") + encounter.getObservationReadableValue("25427c04-d95e-4c9e-a49a-16592b5ee837");

    const allCastTotalUUIDs = [
      'd0b2b320-340e-49aa-95bd-a07464f41c5b',
      '29ddc822-a7bb-4b4d-818e-079cc12fa3d1',
      'e1b1d58f-da4e-4921-b480-c9c70c9ceac2',
      '5390d56b-1211-4229-997a-96710ffc6871',
      '492e8791-720c-4563-9de1-b326e71b0cc9',
      'c8fb85af-7057-4755-9bbf-3e7db2ec1fbd',
      '33f1b340-e0b9-4da2-8ec6-78a33a20ca22',
      'a410999a-cdcd-4a1d-adc1-4c2625dbe5b5'
    ];

    let allCasteTotalSum = 0;
    for(let ind = 0; ind < allCastTotalUUIDs.length; ind++){
      const numberOfChildren = encounter.getObservationReadableValue(allCastTotalUUIDs[ind]);

      if(numberOfChildren == undefined) continue;

      allCasteTotalSum += numberOfChildren;
    }

    if(totalBoysPlusTotalGirls == allCasteTotalSum) value = totalBoysPlusTotalGirls;

    else validationErrors.push(`Sum of "Number of Boys" and "Number of Girls" (is ${totalBoysPlusTotalGirls}) should be equal to the sum of children from different social statuses (is ${allCasteTotalSum}).`);
  }
  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

