'use strict';
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];
  let alreadyDefinedOptions = [];

  const questionGroupIndex = params.questionGroupIndex;

  const questionGroup = encounter.getObservationValue('ff222a00-ecf4-4444-aeca-90bafe8a8f84');

  if (questionGroup != undefined) {

    for (let ind = 0; ind < questionGroup.length; ind++) {

      if (ind == questionGroupIndex) continue;

      const option = questionGroup[ind].findObservationByConceptUUID('e49fc316-3c3c-4de8-bdf3-c776797f7a96');

      if (option != undefined) alreadyDefinedOptions.push(option.getValue());
    }
  }

  _.forEach(alreadyDefinedOptions, (answer) => {
    const answerToSkip = formElement.getAnswerWithConceptUuid(answer);
    if (answerToSkip) answersToSkip.push(answerToSkip);
  });

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

 'use strict';
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = 0;
