  let validationErrors = [];

  const questionGroupIndex = params.questionGroupIndex;

  const currentQuestionGroup = encounter.getObservationValue('ff222a00-ecf4-4444-aeca-90bafe8a8f84')[questionGroupIndex];

  const isTotalChildrenDefined = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.questionGroupValueInEncounter("5e2540d7-494c-4f46-8f98-4d601a140e9e", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("25427c04-d95e-4c9e-a49a-16592b5ee837", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("d0b2b320-340e-49aa-95bd-a07464f41c5b", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("29ddc822-a7bb-4b4d-818e-079cc12fa3d1", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("e1b1d58f-da4e-4921-b480-c9c70c9ceac2", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("5390d56b-1211-4229-997a-96710ffc6871", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("492e8791-720c-4563-9de1-b326e71b0cc9", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("c8fb85af-7057-4755-9bbf-3e7db2ec1fbd", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("33f1b340-e0b9-4da2-8ec6-78a33a20ca22", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined
    .and.when.questionGroupValueInEncounter("a410999a-cdcd-4a1d-adc1-4c2625dbe5b5", "ff222a00-ecf4-4444-aeca-90bafe8a8f84", params.questionGroupIndex).defined.matches();

  visibility = isTotalChildrenDefined;

  if(isTotalChildrenDefined){

    const totalBoysPlusTotalGirls = currentQuestionGroup.findObservationByConceptUUID("5e2540d7-494c-4f46-8f98-4d601a140e9e").getReadableValue() + currentQuestionGroup.findObservationByConceptUUID("25427c04-d95e-4c9e-a49a-16592b5ee837").getReadableValue();

    const allCastTotalUUIDs = [
      'd0b2b320-340e-49aa-95bd-a07464f41c5b',
      '29ddc822-a7bb-4b4d-818e-079cc12fa3d1',
      'e1b1d58f-da4e-4921-b480-c9c70c9ceac2',
