({params, imports}) => {
  const individual = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({individual, formElement});
  const individualService = params.services.individualService;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let answersToShow = [];
  let validationErrors = [];

  const lowestAddressLevel = individual.lowestAddressLevel;

  if(lowestAddressLevel && lowestAddressLevel.type == 'Cluster'){
    //visibility = true;
    const schoolSubjects = individualService.getSubjectsInLocation(lowestAddressLevel, 'School');
    if(schoolSubjects.length){

      answersToShow = _.map(schoolSubjects, ({uuid}) => uuid);
    }
  }

  if(answersToShow.length == 0) validationErrors.push('No schools were found within the selected cluster.');
  /*
  else{
    visibility = false;
  }
  */
  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors, answersToShow);
};
